"use client";

import { useState, type FormEvent } from "react";

const vehicleLinks = [
  { label: "Range Rover", href: "#" },
  { label: "Range Rover Sport", href: "#" },
  { label: "Range Rover Velar", href: "#" },
  { label: "Range Rover Evoque", href: "#" },
  { label: "Defender", href: "#" },
  { label: "Discovery", href: "#" },
  { label: "Discovery Sport", href: "#" },
];

const ownershipLinks = [
  { label: "Accessories", href: "#" },
  { label: "Land Rover Financial Group", href: "#" },
  { label: "Land Rover InControl®", href: "#" },
  { label: "Service & Maintenance", href: "#" },
  { label: "Recall Information", href: "#" },
  { label: "Owner's Manual", href: "#" },
];

const experienceLinks = [
  { label: "Events", href: "#" },
  { label: "Land Rover Experience", href: "#" },
  { label: "Gear", href: "#" },
];

const aboutLinks = [
  { label: "Contact Us", href: "#" },
  { label: "Find a Retailer", href: "#" },
  { label: "Careers", href: "#" },
  { label: "Worldwide", href: "#" },
  { label: "Press", href: "#" },
];

const socialLinks = [
  { label: "Facebook", href: "#", icon: "fb" },
  { label: "Twitter", href: "#", icon: "tw" },
  { label: "Instagram", href: "#", icon: "ig" },
  { label: "YouTube", href: "#", icon: "yt" },
];

const hygieneLinks = [
  { label: "Sitemap", href: "#" },
  { label: "Privacy Policy", href: "#" },
  { label: "Cookie Policy", href: "#" },
  { label: "Terms & Conditions", href: "#" },
  { label: "Accessibility", href: "#" },
  { label: "Do Not Sell My Personal Information", href: "#" },
];

function SocialIcon({ type }: { type: string }) {
  switch (type) {
    case "fb":
      return (
        <svg viewBox="0 0 24 24" className="w-5 h-5 fill-current">
          <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
        </svg>
      );
    case "tw":
      return (
        <svg viewBox="0 0 24 24" className="w-5 h-5 fill-current">
          <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231zm-1.161 17.52h1.833L7.084 4.126H5.117z" />
        </svg>
      );
    case "ig":
      return (
        <svg viewBox="0 0 24 24" className="w-5 h-5 fill-current">
          <path d="M12 2.163c3.204 0 3.584.012 4.85.07 3.252.148 4.771 1.691 4.919 4.919.058 1.265.069 1.645.069 4.849 0 3.205-.012 3.584-.069 4.849-.149 3.225-1.664 4.771-4.919 4.919-1.266.058-1.644.07-4.85.07-3.204 0-3.584-.012-4.849-.07-3.26-.149-4.771-1.699-4.919-4.92-.058-1.265-.07-1.644-.07-4.849 0-3.204.013-3.583.07-4.849.149-3.227 1.664-4.771 4.919-4.919 1.266-.057 1.645-.069 4.849-.069zM12 0C8.741 0 8.333.014 7.053.072 2.695.272.273 2.69.073 7.052.014 8.333 0 8.741 0 12c0 3.259.014 3.668.072 4.948.2 4.358 2.618 6.78 6.98 6.98C8.333 23.986 8.741 24 12 24c3.259 0 3.668-.014 4.948-.072 4.354-.2 6.782-2.618 6.979-6.98.059-1.28.073-1.689.073-4.948 0-3.259-.014-3.667-.072-4.947-.196-4.354-2.617-6.78-6.979-6.98C15.668.014 15.259 0 12 0zm0 5.838a6.162 6.162 0 100 12.324 6.162 6.162 0 000-12.324zM12 16a4 4 0 110-8 4 4 0 010 8zm6.406-11.845a1.44 1.44 0 100 2.881 1.44 1.44 0 000-2.881z" />
        </svg>
      );
    case "yt":
      return (
        <svg viewBox="0 0 24 24" className="w-5 h-5 fill-current">
          <path d="M23.498 6.186a3.016 3.016 0 00-2.122-2.136C19.505 3.545 12 3.545 12 3.545s-7.505 0-9.377.505A3.017 3.017 0 00.502 6.186C0 8.07 0 12 0 12s0 3.93.502 5.814a3.016 3.016 0 002.122 2.136c1.871.505 9.376.505 9.376.505s7.505 0 9.377-.505a3.015 3.015 0 002.122-2.136C24 15.93 24 12 24 12s0-3.93-.502-5.814zM9.545 15.568V8.432L15.818 12l-6.273 3.568z" />
        </svg>
      );
    default:
      return null;
  }
}

export default function Footer() {
  const [email, setEmail] = useState("");

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    // Newsletter signup placeholder
    setEmail("");
  };

  return (
    <footer className="bg-[#0c121c] text-white">
      {/* Newsletter Section */}
      <div className="border-t border-white/10">
        <div className="max-w-[1200px] mx-auto px-6 py-16 text-center">
          <h2 className="text-xs tracking-[0.3em] uppercase font-semibold mb-2">
            SEE WHAT&apos;S COMING
          </h2>
          <p className="text-sm text-white/60 mb-8 max-w-md mx-auto">
            Be the first to know about new vehicles, upcoming events, and more.
          </p>
          <form
            onSubmit={handleSubmit}
            className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto"
          >
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email address"
              required
              className="flex-1 bg-transparent border border-white/30 px-4 py-3 text-sm text-white placeholder:text-white/40 focus:outline-none focus:border-white transition-colors"
            />
            <button
              type="submit"
              className="bg-white text-[#0c121c] text-xs tracking-[0.2em] uppercase font-semibold px-8 py-3 hover:bg-white/90 transition-colors"
            >
              Subscribe
            </button>
          </form>
        </div>
      </div>

      {/* Footer Navigation */}
      <div className="border-t border-white/10">
        <div className="max-w-[1200px] mx-auto px-6 py-12">
          <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-8">
            {/* Our Vehicles */}
            <div>
              <h3 className="text-xs tracking-[0.2em] uppercase font-semibold mb-4">
                Our Vehicles
              </h3>
              <ul className="space-y-2">
                {vehicleLinks.map((link) => (
                  <li key={link.label}>
                    <a
                      href={link.href}
                      className="text-sm text-white/60 hover:text-white transition-colors"
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>

            {/* Ownership */}
            <div>
              <h3 className="text-xs tracking-[0.2em] uppercase font-semibold mb-4">
                Ownership
              </h3>
              <ul className="space-y-2">
                {ownershipLinks.map((link) => (
                  <li key={link.label}>
                    <a
                      href={link.href}
                      className="text-sm text-white/60 hover:text-white transition-colors"
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>

            {/* Experience */}
            <div>
              <h3 className="text-xs tracking-[0.2em] uppercase font-semibold mb-4">
                Experience
              </h3>
              <ul className="space-y-2">
                {experienceLinks.map((link) => (
                  <li key={link.label}>
                    <a
                      href={link.href}
                      className="text-sm text-white/60 hover:text-white transition-colors"
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>

            {/* About Land Rover */}
            <div>
              <h3 className="text-xs tracking-[0.2em] uppercase font-semibold mb-4">
                About Land Rover
              </h3>
              <ul className="space-y-2">
                {aboutLinks.map((link) => (
                  <li key={link.label}>
                    <a
                      href={link.href}
                      className="text-sm text-white/60 hover:text-white transition-colors"
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
              </ul>
            </div>

            {/* Social */}
            <div>
              <h3 className="text-xs tracking-[0.2em] uppercase font-semibold mb-4">
                Social
              </h3>
              <div className="flex gap-4">
                {socialLinks.map((link) => (
                  <a
                    key={link.label}
                    href={link.href}
                    aria-label={link.label}
                    className="text-white/60 hover:text-white transition-colors"
                  >
                    <SocialIcon type={link.icon} />
                  </a>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Search Bar */}
      <div className="border-t border-white/10">
        <div className="max-w-[1200px] mx-auto px-6 py-6">
          <div className="flex items-center gap-3 max-w-md">
            <svg
              width="18"
              height="18"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              className="text-white/40 flex-shrink-0"
            >
              <circle cx="11" cy="11" r="8" />
              <path d="m21 21-4.35-4.35" />
            </svg>
            <input
              type="search"
              placeholder="Search landroverusa.com"
              className="w-full bg-transparent text-sm text-white placeholder:text-white/40 focus:outline-none border-b border-white/20 pb-1 focus:border-white transition-colors"
            />
          </div>
        </div>
      </div>

      {/* Hygiene Links */}
      <div className="border-t border-white/10">
        <div className="max-w-[1200px] mx-auto px-6 py-6">
          <div className="flex flex-wrap gap-x-6 gap-y-2">
            {hygieneLinks.map((link) => (
              <a
                key={link.label}
                href={link.href}
                className="text-xs text-white/40 hover:text-white/60 transition-colors"
              >
                {link.label}
              </a>
            ))}
          </div>
        </div>
      </div>

      {/* Sub Footer */}
      <div className="border-t border-white/10">
        <div className="max-w-[1200px] mx-auto px-6 py-8">
          <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
            {/* Land Rover Logo */}
            <div
              className="text-lg tracking-[0.3em] uppercase text-white/60"
              style={{ fontFamily: "LandRoverWeb-Bold, sans-serif" }}
            >
              LAND ROVER
            </div>

            <p className="text-xs text-white/30 leading-relaxed max-w-2xl">
              © 2026 Jaguar Land Rover North America, LLC. All rights reserved.
              Land Rover, Range Rover, Defender, Discovery, InControl and the
              Land Rover logo are registered trademarks of Jaguar Land Rover
              Limited. Jaguar Land Rover Limited is not the parent company of
              Jaguar Land Rover North America, LLC.
            </p>
          </div>

          <div className="mt-6 space-y-3">
            <p className="text-[11px] text-white/25 leading-relaxed">
              1. European model shown. U.S. model may vary. 2. All prices shown
              are Manufacturer&apos;s Suggested Retail Price. Excludes
              destination/handling charge, tax, title, license, and retailer
              fees, all due at signing, and optional equipment. Retailer price,
              terms and vehicle availability may vary. See your local authorized
              Land Rover Retailer for best price.
            </p>
            <p className="text-[11px] text-white/25 leading-relaxed">
              3. Always follow local speed limits. Do not use Land Rover vehicles
              to race or compete against other vehicles. 4. Towing capacity
              varies by configuration. See Owner&apos;s Manual for details.
            </p>
          </div>
        </div>
      </div>
    </footer>
  );
}
