"use client";

import { useState } from "react";

interface BrandPanel {
  id: string;
  name: string;
  logoText: string;
  href: string;
  image: string;
  video: string;
}

const brands: BrandPanel[] = [
  {
    id: "range-rover",
    name: "Range Rover",
    logoText: "RANGE ROVER",
    href: "https://www.landroverusa.com/range-rover/index.html",
    image:
      "https://jlr.scene7.com/is/image/jlr/DX_INTRO_STILL_L460?qlt=85&wid=1920&fmt=webp",
    video:
      "https://jlr.scene7.com/is/content/jlr/DX_INTRO_L460",
  },
  {
    id: "defender",
    name: "Defender",
    logoText: "DEFENDER",
    href: "https://www.landroverusa.com/defender/index.html",
    image:
      "https://jlr.scene7.com/is/image/jlr/DX_INTRO_STILL_L663?qlt=85&wid=1920&fmt=webp",
    video:
      "https://jlr.scene7.com/is/content/jlr/DX_INTRO_L663",
  },
  {
    id: "discovery",
    name: "Discovery",
    logoText: "DISCOVERY",
    href: "https://www.landroverusa.com/discovery/index.html",
    image:
      "https://jlr.scene7.com/is/image/jlr/DX_INTRO_STILL_L462?qlt=85&wid=1920&fmt=webp",
    video:
      "https://jlr.scene7.com/is/content/jlr/DX_INTRO_L462",
  },
];

export default function HeroBrands() {
  const [hoveredId, setHoveredId] = useState<string | null>(null);

  return (
    <section className="relative w-full min-h-screen">
      {/* Title */}
      <div className="absolute top-20 left-0 right-0 z-20 text-center pt-8">
        <h1 className="text-white text-xs sm:text-sm tracking-[0.25em] uppercase font-medium">
          Choose from Range Rover, Defender or Discovery
        </h1>
      </div>

      {/* Brand Panels */}
      <div className="flex flex-col lg:flex-row w-full min-h-screen">
        {brands.map((brand) => {
          const isHovered = hoveredId === brand.id;
          const isOtherHovered = hoveredId !== null && hoveredId !== brand.id;

          return (
            <a
              key={brand.id}
              href={brand.href}
              className={`relative flex-1 flex flex-col items-center justify-center overflow-hidden transition-all duration-700 ease-in-out min-h-[33.33vh] lg:min-h-screen ${
                isHovered ? "lg:flex-[2]" : isOtherHovered ? "lg:flex-[0.5]" : "lg:flex-1"
              }`}
              onMouseEnter={() => setHoveredId(brand.id)}
              onMouseLeave={() => setHoveredId(null)}
            >
              {/* Background Image */}
              <div
                className="absolute inset-0 bg-cover bg-center transition-transform duration-700"
                style={{ backgroundImage: `url(${brand.image})` }}
              />

              {/* Video (shows on hover) */}
              {isHovered && (
                <video
                  className="absolute inset-0 w-full h-full object-cover"
                  src={brand.video}
                  autoPlay
                  muted
                  loop
                  playsInline
                />
              )}

              {/* Gradient overlay */}
              <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-black/30" />

              {/* Content */}
              <div className="relative z-10 flex flex-col items-center justify-center gap-6">
                {/* Brand Logo Text */}
                <h2
                  className="text-white text-2xl sm:text-3xl lg:text-4xl tracking-[0.3em] uppercase"
                  style={{ fontFamily: "LandRoverWeb-Bold, sans-serif" }}
                >
                  {brand.logoText}
                </h2>

                {/* Enter Button */}
                <div
                  className={`transition-all duration-500 ${
                    isHovered
                      ? "opacity-100 translate-y-0"
                      : "opacity-0 translate-y-4 lg:opacity-0"
                  }`}
                >
                  <span className="inline-block border border-white text-white text-xs tracking-[0.25em] uppercase px-8 py-3 hover:bg-white hover:text-[#0c121c] transition-colors duration-300">
                    ENTER
                  </span>
                </div>
              </div>

              {/* Divider lines between panels */}
              <div className="hidden lg:block absolute right-0 top-[15%] bottom-[15%] w-px bg-white/20" />
            </a>
          );
        })}
      </div>
    </section>
  );
}
